Bash(powershell -Command "
Write-Host '=== Cline API conversation sizes \(proxy for token consumption\) ==='
\\$base = \\"\\$env:APPDATA\\\\Code\\\\User\\\\globalStorage\\\\saoudrizwan.claude-dev\\\\tasks\\"
\\$total = 0
Get-ChildItem \\$base -Directory | ForEach-Object {
    \\$taskDir = \\$_.Name
    \\$apiFile = Join-Path \\$_.FullName 'api_conversation_history.json'
    \\$mdFile = Join-Path \\$_.FullName 'focus_chain_taskid_' + \\$taskDir + '.md'
    \\$apiSize = if \(Test-Path \\$apiFile\) { \(Get-Item \\$apiFile\).Length } else { 0 }
    \\$uiSize = if \(Test-Path \(Join-Path \\$_.FullName 'ui_messages.json'\)\) { \(Get-Item \(Join-Path \\$_.FullName 'ui_messages.json'\)\).Length } else { 0 }
    \\$desc = if \(Test-Path \\$mdFile\) { \(Get-Content \\$mdFile -Raw\).Trim\(\) } else { 'N/A' }
    \\$total += \\$apiSize
    [PSCustomObject]@{
        Task=\\$taskDir.Substring\(0,13\)
        API_KB=[math]::Round\(\\$apiSize/1024, 0\)
        UI_KB=[math]::Round\(\\$uiSize/1024, 0\)
        API_LastWrite=\(Get-Item \\$apiFile\).LastWriteTime
        Description=\\$desc.Substring\(0, [Math]::Min\(80, \\$desc.Length\)\)
    }
} | Sort-Object API_LastWrite -Descending | Format-Table -AutoSize
Write-Host \('Total API conversation JSON: ' + [math]::Round\(\\$total/1024, 0\) + ' KB'\)
")

